document.addEventListener('DOMContentLoaded', () => {
 const mainImage = document.getElementById('mainProductImage');
 const productInfo = document.getElementById('productDetailInfo');
 const defaultImage = productInfo?.dataset.defaultImage ?? '';
 document.querySelectorAll('.product-detail-variation-row[data-image]').forEach((row) => {
 const preview = () => {
 if (mainImage && mainImage.tagName === 'IMG' && row.dataset.image) {
 mainImage.src = row.dataset.image;
 }
 };
 row.addEventListener('mouseenter', preview);
 row.addEventListener('focusin', preview);
 });
 document.getElementById('detailVariations')?.addEventListener('mouseleave', () => {
 if (mainImage && mainImage.tagName === 'IMG' && defaultImage) {
 mainImage.src = defaultImage;
 }
 });
 const thumbnails = document.querySelectorAll('.product-thumbnail');
 thumbnails.forEach((thumb) => {
 thumb.addEventListener('click', () => {
 if (!mainImage || mainImage.tagName !== 'IMG') return;
 const src = thumb.dataset.src;
 if (src) {
 mainImage.src = src;
 if (thumb.dataset.srcset) {
 mainImage.srcset = thumb.dataset.srcset;
 } else {
 mainImage.removeAttribute('srcset');
 }
 if (thumb.dataset.width) mainImage.width = thumb.dataset.width;
 if (thumb.dataset.height) mainImage.height = thumb.dataset.height;
 thumbnails.forEach((t) => t.classList.remove('active'));
 thumb.classList.add('active');
 }
 });
 });
 const backBtn = document.getElementById('productDetailBack');
 if (backBtn && document.referrer && window.history.length > 1) {
 backBtn.addEventListener('click', (event) => {
 event.preventDefault();
 history.back();
 });
 }
 function getCsrfToken() {
 const match = document.cookie.match(/csrftoken=([^;]+)/);
 return match ? decodeURIComponent(match[1]) : '';
 }
 function triggerCartAddPulse(cartBtn) {
 cartBtn.classList.remove('cart-btn--pulse-once');
 void cartBtn.offsetWidth;
 cartBtn.classList.add('cart-btn--pulse-once');
 const svg = cartBtn.querySelector('.cart-btn-svg');
 if (!svg) {
 cartBtn.classList.remove('cart-btn--pulse-once');
 return;
 }
 const clearPulse = (event) => {
 if (event.animationName !== 'cart-icon-add-pulse') return;
 cartBtn.classList.remove('cart-btn--pulse-once');
 svg.removeEventListener('animationend', clearPulse);
 };
 svg.addEventListener('animationend', clearPulse);
 }
 function updateCartBadge(count) {
 const cartBtn = document.querySelector('.cart-btn');
 if (!cartBtn) return;
 const previousCount = parseInt(cartBtn.dataset.cartCount || '0', 10);
 const nextCount = Math.max(0, parseInt(count, 10) || 0);
 let badge = cartBtn.querySelector('.cart-badge');
 if (nextCount > 0) {
 cartBtn.classList.add('cart-btn--has-items');
 if (!badge) {
 badge = document.createElement('span');
 badge.className = 'cart-badge';
 cartBtn.appendChild(badge);
 }
 badge.textContent = nextCount;
 if (nextCount > previousCount) {
 triggerCartAddPulse(cartBtn);
 }
 } else {
 cartBtn.classList.remove('cart-btn--has-items', 'cart-btn--pulse-once');
 if (badge) {
 badge.remove();
 }
 }
 cartBtn.dataset.cartCount = String(nextCount);
 }
 function showCartToast(message) {
 let toast = document.querySelector('.cart-toast');
 if (!toast) {
 toast = document.createElement('p');
 toast.className = 'cart-toast';
 document.body.appendChild(toast);
 }
 toast.textContent = message;
 toast.classList.add('cart-toast--visible');
 clearTimeout(showCartToast.timer);
 showCartToast.timer = setTimeout(() => {
 toast.classList.remove('cart-toast--visible');
 }, 2200);
 }
 const gratisOverlay = document.getElementById('gratisOfferOverlay');
 const gratisImage = document.getElementById('gratisOfferImage');
 const gratisTitle = document.getElementById('gratisOfferTitle');
 const gratisText = document.getElementById('gratisOfferText');
 const gratisHeadline = document.getElementById('gratisOfferHeadline');
 const gratisLabel = document.getElementById('gratisOfferLabel');
 const gratisBadge = document.getElementById('gratisOfferBadge');
 const gratisPrices = document.getElementById('gratisOfferPrices');
 const gratisOriginal = document.getElementById('gratisOfferOriginal');
 const gratisDiscounted = document.getElementById('gratisOfferDiscounted');
 const gratisAccept = document.getElementById('gratisOfferAccept');
 const gratisDecline = document.getElementById('gratisOfferDecline');
 const gratisClose = document.getElementById('gratisOfferClose');
 const gratisQtyInput = document.getElementById('gratisOfferQty');
 const gratisQtyMinus = document.getElementById('gratisOfferQtyMinus');
 const gratisQtyPlus = document.getElementById('gratisOfferQtyPlus');
 let pendingGratisForm = null;
 let pendingGratisOffer = null;
 function ponudaAnsweredKey(akcijaId) {
 return `ponuda_answered_${akcijaId}`;
 }
 function markPonudaAnsweredClient(akcijaId) {
 if (!akcijaId) return;
 try {
 sessionStorage.setItem(ponudaAnsweredKey(akcijaId), '1');
 } catch (e) {}
 }
 function isPonudaAnsweredClient(akcijaId) {
 if (!akcijaId) return false;
 try {
 return sessionStorage.getItem(ponudaAnsweredKey(akcijaId)) === '1';
 } catch (e) {
 return false;
 }
 }
 function getGratisOfferQty() {
 if (!gratisQtyInput) return 1;
 let n = parseInt(gratisQtyInput.value, 10);
 if (!Number.isFinite(n) || n < 1) n = 1;
 if (n > 99) n = 99;
 return n;
 }
 function setGratisOfferQty(value) {
 if (!gratisQtyInput) return;
 let n = parseInt(value, 10);
 if (!Number.isFinite(n) || n < 1) n = 1;
 if (n > 99) n = 99;
 gratisQtyInput.value = String(n);
 if (gratisQtyMinus) gratisQtyMinus.disabled = n <= 1;
 if (gratisQtyPlus) gratisQtyPlus.disabled = n >= 99;
 }
 function syncGratisQtyButtons() {
 setGratisOfferQty(getGratisOfferQty());
 }
 function closeGratisOfferModal() {
 if (!gratisOverlay) return;
 gratisOverlay.classList.remove('is-visible');
 gratisOverlay.hidden = true;
 document.body.classList.remove('popup-open');
 pendingGratisForm = null;
 pendingGratisOffer = null;
 }
 function fillGratisOfferModal(offer) {
 if (gratisLabel) {
 gratisLabel.textContent = offer.label || 'Dobra kupovina';
 }
 if (gratisTitle) gratisTitle.textContent = offer.gratis_naziv || '';
 if (gratisHeadline) {
 gratisHeadline.textContent = offer.headline || '';
 gratisHeadline.hidden = !offer.headline;
 }
 if (gratisText) {
 if (offer.has_discount) {
 const pctHtml = offer.is_full_discount
 ? '<strong class="gratis-offer-pct">GRATIS</strong>'
 : `<strong class="gratis-offer-pct">−${offer.pct}%</strong>`;
 gratisText.innerHTML =
 `Želite li uz ovaj artikal i ovo sa <strong>AKCIJSKOM</strong> cijenom ${pctHtml}?`;
 } else {
 gratisText.innerHTML = 'Želite li uz ovaj artikal i ovo?';
 }
 }
 if (gratisImage) {
 if (offer.slika_url) {
 gratisImage.src = offer.slika_url;
 gratisImage.alt = offer.gratis_naziv || '';
 gratisImage.hidden = false;
 } else {
 gratisImage.removeAttribute('src');
 gratisImage.alt = '';
 gratisImage.hidden = true;
 }
 }
 if (gratisPrices && gratisOriginal && gratisDiscounted) {
 if (offer.has_discount) {
 gratisOriginal.textContent = `${offer.original_price} KM`;
 gratisOriginal.hidden = false;
 gratisDiscounted.textContent = `${offer.discounted_price} KM`;
 } else {
 gratisOriginal.textContent = '';
 gratisOriginal.hidden = true;
 gratisDiscounted.textContent =
 `${offer.discounted_price || offer.original_price} KM`;
 }
 gratisPrices.hidden = false;
 }
 if (gratisBadge) {
 if (offer.badge) {
 gratisBadge.textContent = offer.badge;
 gratisBadge.hidden = false;
 } else {
 gratisBadge.textContent = '';
 gratisBadge.hidden = true;
 }
 }
 setGratisOfferQty(1);
 if (gratisAccept) gratisAccept.textContent = 'DA';
 if (gratisDecline) gratisDecline.textContent = 'NE';
 }
 function openGratisOfferModal(offer, form) {
 if (!gratisOverlay || !offer || !form) return;
 pendingGratisForm = form;
 pendingGratisOffer = offer;
 fillGratisOfferModal(offer);
 gratisOverlay.hidden = false;
 requestAnimationFrame(() => {
 gratisOverlay.classList.add('is-visible');
 });
 document.body.classList.add('popup-open');
 }
 async function submitGratisChoice(choice) {
 if (!pendingGratisForm || !pendingGratisOffer) return;
 const form = pendingGratisForm;
 const offer = pendingGratisOffer;
 const offerQty = getGratisOfferQty();
 markPonudaAnsweredClient(offer.akcija_id);
 closeGratisOfferModal();
 await submitAddToCartForm(form, {
 gratis_choice: choice,
 gratis_akcija_id: String(offer.akcija_id),
 gratis_quantity: String(choice === 'yes' ? offerQty : 1),
 });
 }
 if (gratisQtyMinus && !gratisQtyMinus.dataset.ponudaBound) {
 gratisQtyMinus.dataset.ponudaBound = '1';
 gratisQtyMinus.addEventListener('click', (e) => {
 e.preventDefault();
 e.stopPropagation();
 setGratisOfferQty(getGratisOfferQty() - 1);
 });
 }
 if (gratisQtyPlus && !gratisQtyPlus.dataset.ponudaBound) {
 gratisQtyPlus.dataset.ponudaBound = '1';
 gratisQtyPlus.addEventListener('click', (e) => {
 e.preventDefault();
 e.stopPropagation();
 setGratisOfferQty(getGratisOfferQty() + 1);
 });
 }
 if (gratisQtyInput && !gratisQtyInput.dataset.ponudaBound) {
 gratisQtyInput.dataset.ponudaBound = '1';
 gratisQtyInput.addEventListener('change', syncGratisQtyButtons);
 gratisQtyInput.addEventListener('input', syncGratisQtyButtons);
 }
 if (gratisAccept && !gratisAccept.dataset.ponudaBound) {
 gratisAccept.dataset.ponudaBound = '1';
 gratisAccept.addEventListener('click', () => submitGratisChoice('yes'));
 }
 if (gratisDecline && !gratisDecline.dataset.ponudaBound) {
 gratisDecline.dataset.ponudaBound = '1';
 gratisDecline.addEventListener('click', () => submitGratisChoice('no'));
 }
 if (gratisClose && !gratisClose.dataset.ponudaBound) {
 gratisClose.dataset.ponudaBound = '1';
 gratisClose.addEventListener('click', () => submitGratisChoice('no'));
 }
 async function submitAddToCartForm(form, extraFields = {}) {
 const submitBtn = form.querySelector('[type="submit"]');
 const body = new URLSearchParams(new FormData(form));
 body.set('stay', '1');
 Object.entries(extraFields).forEach(([key, value]) => {
 body.set(key, value);
 });
 if (submitBtn) submitBtn.disabled = true;
 try {
 const response = await fetch(form.action, {
 method: 'POST',
 headers: {
 'Content-Type': 'application/x-www-form-urlencoded',
 'X-CSRFToken': getCsrfToken(),
 'X-Requested-With': 'XMLHttpRequest',
 },
 body: body.toString(),
 });
 const data = await response.json();
 if (!response.ok || !data.ok) {
 throw new Error(data.message || 'Dodavanje u korpu nije uspjelo.');
 }
 if (data.requires_gratis_choice && data.gratis_offer) {
 if (isPonudaAnsweredClient(data.gratis_offer.akcija_id)) {
 await submitAddToCartForm(form, {
 gratis_choice: 'no',
 gratis_akcija_id: String(data.gratis_offer.akcija_id),
 gratis_quantity: '1',
 });
 return;
 }
 openGratisOfferModal(data.gratis_offer, form);
 return;
 }
 updateCartBadge(data.cart_count);
 showCartToast(data.message);
 if (data.upsell_html && typeof window.handleUpsellResponse === 'function') {
 window.handleUpsellResponse(data.upsell_html);
 }
 if (data.meta_add_to_cart && typeof window.trackMetaAddToCart === 'function') {
 window.trackMetaAddToCart(data.meta_add_to_cart);
 }
 } catch (err) {
 showCartToast(err.message || 'Dodavanje u korpu nije uspjelo.');
 } finally {
 if (submitBtn) submitBtn.disabled = false;
 }
 }
 document.querySelectorAll('form.add-to-cart-form, form.product-detail-variation-form').forEach((form) => {
 form.addEventListener('submit', (event) => {
 event.preventDefault();
 submitAddToCartForm(form);
 });
 });
 document.querySelectorAll('.product-qty-selector').forEach((selector) => {
 if (selector.hasAttribute('data-ponuda-qty') || selector.closest('#gratisOfferOverlay')) {
 return;
 }
 const input = selector.querySelector('.product-qty-input');
 const minusBtn = selector.querySelector('.product-qty-btn--minus');
 const plusBtn = selector.querySelector('.product-qty-btn--plus');
 if (!input || !minusBtn || !plusBtn) return;
 if (input.id === 'gratisOfferQty') return;
 const min = Number.parseInt(input.min, 10) || 1;
 const max = Number.parseInt(input.max, 10) || 99;
 const syncButtons = () => {
 const value = Number.parseInt(input.value, 10) || min;
 minusBtn.disabled = value <= min;
 plusBtn.disabled = value >= max;
 };
 minusBtn.addEventListener('click', () => {
 const value = Number.parseInt(input.value, 10) || min;
 if (value > min) {
 input.value = String(value - 1);
 syncButtons();
 }
 });
 plusBtn.addEventListener('click', () => {
 const value = Number.parseInt(input.value, 10) || min;
 if (value < max) {
 input.value = String(value + 1);
 syncButtons();
 }
 });
 input.addEventListener('change', () => {
 let value = Number.parseInt(input.value, 10);
 if (!Number.isFinite(value) || value < min) value = min;
 if (value > max) value = max;
 input.value = String(value);
 syncButtons();
 });
 syncButtons();
 });
 (function initDwellFlashPrice() {
 const cfgEl = document.getElementById('dwellFlashConfigData');
 if (!cfgEl) return;
 let cfg;
 try {
 cfg = JSON.parse(cfgEl.textContent || '{}');
 } catch (e) {
 return;
 }
 if (!cfg || !cfg.active || !cfg.product_id || !cfg.flash) return;
 const flashBox = document.getElementById('pdDwellFlash');
 const countdownEl = document.getElementById('pdDwellCountdown');
 const wasEl = document.getElementById('pdDwellWas');
 const nowEl = document.getElementById('pdDwellNow');
 const badgeEl = document.getElementById('pdDwellBadge');
 const detailPrice = document.getElementById('detailPrice');
 if (!flashBox || !countdownEl) return;
 const flashSec = Math.max(30, parseInt(cfg.flash_seconds || 120, 10) || 120);
 let tickTimer = null;
 function fmt(sec) {
 sec = Math.max(0, Math.floor(sec));
 const m = Math.floor(sec / 60);
 const s = sec % 60;
 return m + ':' + String(s).padStart(2, '0');
 }
 function formatKm(val) {
 const n = Number(val);
 if (!Number.isFinite(n)) return String(val) + ' KM';
 return n.toFixed(2).replace('.', ',') + ' KM';
 }
 function hideFlash() {
 flashBox.hidden = true;
 flashBox.classList.remove('is-active');
 if (detailPrice) detailPrice.hidden = false;
 if (tickTimer) {
 clearInterval(tickTimer);
 tickTimer = null;
 }
 document.body.classList.remove('pd-dwell-flash-on');
 }
 function showFlash(data) {
 const base = data.base || cfg.base_price;
 const sale = data.sale;
 const pct = data.percent || cfg.percent || 10;
 let remaining = parseInt(data.remaining_seconds || 0, 10) || 0;
 if (remaining <= 0) {
 hideFlash();
 return;
 }
 if (wasEl) {
 wasEl.textContent = formatKm(base);
 }
 if (nowEl) {
 nowEl.textContent = formatKm(sale);
 }
 if (badgeEl) {
 badgeEl.textContent = '−' + pct + '%';
 }
 if (detailPrice) detailPrice.hidden = true;
 flashBox.hidden = false;
 flashBox.classList.add('is-active');
 document.body.classList.add('pd-dwell-flash-on');
 countdownEl.textContent = fmt(remaining);
 if (tickTimer) clearInterval(tickTimer);
 tickTimer = setInterval(function () {
 remaining -= 1;
 if (remaining <= 0) {
 hideFlash();
 return;
 }
 countdownEl.textContent = fmt(remaining);
 }, 1000);
 }
 const rem = parseInt(cfg.flash.remaining_seconds || 0, 10) || 0;
 if (rem > 0 && cfg.flash.sale) {
 showFlash({
 base: cfg.flash.base || cfg.base_price,
 sale: cfg.flash.sale,
 percent: cfg.flash.percent || cfg.percent,
 remaining_seconds: rem,
 });
 } else {
 hideFlash();
 }
 })();
});
